from __future__ import annotations

import re
from pathlib import Path

ROOT_DIR = Path(__file__).resolve().parent.parent
INPUT_FILE = ROOT_DIR / ".env.example"
OUTPUT_FILE = ROOT_DIR / "docs" / "snippets" / "environment-variables.mdx"

AUTO_GENERATED_COMMENT = (
    "{/* Auto-generated by scripts/generate_env_docs.py; do not edit by hand. */}"
)

SECTION_HEADER_RE = re.compile(r"^#\s*-{2,}\s*(.+?)\s*-{2,}\s*$")

# Sections to skip entirely.
SKIP_SECTIONS = {"Cloud only"}

# Rename raw section headers to cleaner display names.
SECTION_DISPLAY_NAMES: dict[str, str] = {
    "Shared env vars": "General",
    "Caddy env vars": "Caddy",
    "Frontend env vars": "Frontend",
    "App and DB env vars": "Application",
}


def _escape_pipe(text: str) -> str:
    return text.replace("|", "\\|")


def _parse_env_example(path: Path) -> list[tuple[str, list[tuple[str, str, str]]]]:
    """Parse .env.example into a list of (section_name, [(var, default, desc), ...])."""
    sections: list[tuple[str, list[tuple[str, str, str]]]] = []
    current_section = "General"
    current_vars: list[tuple[str, str, str]] = []
    comment_buf: list[str] = []
    skip = False

    for raw_line in path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()

        # Check for section header.
        m = SECTION_HEADER_RE.match(line)
        if m:
            # Flush previous section.
            if current_vars:
                sections.append((current_section, current_vars))
                current_vars = []
            comment_buf.clear()

            section_name = m.group(1).strip()
            skip = section_name in SKIP_SECTIONS
            current_section = SECTION_DISPLAY_NAMES.get(section_name, section_name)
            continue

        if skip:
            continue

        # Blank line resets comment buffer.
        if not line:
            comment_buf.clear()
            continue

        # Comment line.
        if line.startswith("#"):
            text = line.lstrip("#").strip()
            if text:
                comment_buf.append(text)
            continue

        # Variable line: VAR=value
        if "=" in line:
            var, _, default = line.partition("=")
            var = var.strip()
            default = default.strip().strip('"')
            desc = " ".join(comment_buf)
            comment_buf.clear()
            current_vars.append((var, default, desc))

    # Flush last section.
    if current_vars:
        sections.append((current_section, current_vars))

    return sections


def _render_mdx(sections: list[tuple[str, list[tuple[str, str, str]]]]) -> str:
    lines: list[str] = [AUTO_GENERATED_COMMENT, ""]

    for section_name, variables in sections:
        lines.append(f"## {section_name}")
        lines.append("")
        lines.append("| Variable | Default | Description |")
        lines.append("| :------- | :------ | :---------- |")
        for var, default, desc in variables:
            default_cell = f"`{_escape_pipe(default)}`" if default else ""
            desc_cell = _escape_pipe(desc)
            lines.append(f"| `{var}` | {default_cell} | {desc_cell} |")
        lines.append("")

    return "\n".join(lines)


def main() -> None:
    sections = _parse_env_example(INPUT_FILE)
    mdx = _render_mdx(sections)
    OUTPUT_FILE.write_text(mdx, encoding="utf-8")


if __name__ == "__main__":
    main()
